import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import API from '../../services/axios';

function AdminDashboard() {
  const [stats, setStats] = useState({ totalEvents: 0, totalBookings: 0, totalRevenue: 0 });
  const [recentBookings, setRecentBookings] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => { fetchData(); }, []);

  const fetchData = async () => {
    try {
      const [eventsRes, bookingsRes, paymentsRes] = await Promise.all([
        API.get('/events'),
        API.get('/bookings/all/bookings'),
        API.get('/payments/all/payments'),
      ]);
      setStats({
        totalEvents: eventsRes.data.count || 0,
        totalBookings: bookingsRes.data.count || 0,
        totalRevenue: paymentsRes.data.totalRevenue || 0,
      });
      setRecentBookings(bookingsRes.data.bookings?.slice(0, 5) || []);
    } catch (err) {
      console.error('Dashboard error:', err);
    } finally {
      setLoading(false);
    }
  };

  const statCards = [
    { label: 'Total Events', value: stats.totalEvents, icon: '🎭', color: 'from-blue-500 to-blue-600' },
    { label: 'Total Bookings', value: stats.totalBookings, icon: '🎫', color: 'from-green-500 to-green-600' },
    { label: 'Total Revenue', value: `₹${stats.totalRevenue.toLocaleString()}`, icon: '💰', color: 'from-purple-500 to-purple-600' },
  ];

  if (loading) return (
    <div className="flex items-center justify-center min-h-screen">
      <div className="text-center">
        <div className="text-5xl mb-4 animate-bounce">🎉</div>
        <p className="text-gray-500 text-lg">Loading dashboard...</p>
      </div>
    </div>
  );

  return (
    <div className="p-8">

      {/* Header */}
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-gray-800">Admin Dashboard</h1>
        <p className="text-gray-500 mt-1">Welcome back! Here's what's happening.</p>
      </div>

      {/* Stat Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
        {statCards.map((card) => (
          <div key={card.label} className={`bg-gradient-to-r ${card.color} rounded-2xl p-6 text-white shadow-lg`}>
            <div className="flex justify-between items-center">
              <div>
                <p className="text-white/80 text-sm font-medium">{card.label}</p>
                <p className="text-3xl font-bold mt-1">{card.value}</p>
              </div>
              <span className="text-5xl opacity-80">{card.icon}</span>
            </div>
          </div>
        ))}
      </div>

      {/* Quick Actions */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
        {[
          { to: '/admin/create-event', icon: '➕', label: 'Create Event', desc: 'Add a new event', color: 'hover:border-blue-400' },
          { to: '/admin/manage-events', icon: '📝', label: 'Manage Events', desc: 'Edit or delete events', color: 'hover:border-purple-400' },
          { to: '/admin/bookings', icon: '📊', label: 'View Bookings', desc: 'All customer bookings', color: 'hover:border-green-400' },
        ].map((action) => (
          <Link key={action.to} to={action.to}
            className={`bg-white rounded-2xl p-6 shadow-sm border-2 border-transparent ${action.color} transition-all hover:shadow-md`}>
            <div className="text-4xl mb-3">{action.icon}</div>
            <h3 className="font-bold text-gray-800">{action.label}</h3>
            <p className="text-gray-500 text-sm mt-1">{action.desc}</p>
          </Link>
        ))}
      </div>

      {/* Recent Bookings */}
      <div className="bg-white rounded-2xl shadow-sm p-6">
        <h2 className="text-xl font-bold text-gray-800 mb-4">Recent Bookings</h2>
        {recentBookings.length === 0 ? (
          <div className="text-center py-10">
            <div className="text-5xl mb-3">📦</div>
            <p className="text-gray-400">No bookings yet</p>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b text-gray-500 text-left">
                  <th className="pb-3 px-2">ID</th>
                  <th className="pb-3 px-2">User</th>
                  <th className="pb-3 px-2">Event</th>
                  <th className="pb-3 px-2">Tickets</th>
                  <th className="pb-3 px-2">Amount</th>
                  <th className="pb-3 px-2">Status</th>
                </tr>
              </thead>
              <tbody>
                {recentBookings.map((b) => (
                  <tr key={b._id} className="border-b hover:bg-gray-50">
                    <td className="py-3 px-2 font-mono text-xs text-gray-400">#{b._id.slice(-6).toUpperCase()}</td>
                    <td className="py-3 px-2 font-medium">{b.user?.name}</td>
                    <td className="py-3 px-2">{b.event?.name}</td>
                    <td className="py-3 px-2">{b.numberOfTickets}</td>
                    <td className="py-3 px-2 font-semibold">₹{b.totalAmount}</td>
                    <td className="py-3 px-2">
                      <span className={`px-2 py-1 rounded-full text-xs font-semibold ${
                        b.status === 'confirmed' ? 'bg-green-100 text-green-700' :
                        b.status === 'pending' ? 'bg-yellow-100 text-yellow-700' :
                        'bg-red-100 text-red-700'}`}>
                        {b.status}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

export default AdminDashboard;
